## Implementation

### Line Range Parsing

```rust
use std::str::FromStr;

fn parse_line_ranges(s: &str) -> Result<Vec<LineRange>, String> {
    test_log!("DEBUG", "Parsing line ranges: {}", s);

    let mut ranges = Vec::new();

    for part in s.split(',') {
        let part = part.trim();
        let range = parse_single_range(part)?;
        ranges.push(range);
    }

    // Sort and merge overlapping ranges
    ranges.sort_by_key(|r| r.start);
    let merged = merge_ranges(ranges);

    test_log!("DEBUG", "Parsed ranges: {:?}", merged);
    Ok(merged)
}

fn parse_single_range(s: &str) -> Result<LineRange, String> {
    if s.contains('-') {
        let parts: Vec<&str> = s.splitn(2, '-').collect();

        let start = if parts[0].is_empty() {
            1  // "-100" means "1-100"
        } else {
            parts[0].parse::<usize>()
                .map_err(|_| format!("Invalid start line: {}", parts[0]))?
        };

        let end = if parts.len() < 2 || parts[1].is_empty() {
            usize::MAX  // "50-" means "50 to end"
        } else {
            parts[1].parse::<usize>()
                .map_err(|_| format!("Invalid end line: {}", parts[1]))?
        };

        if start > end && end != usize::MAX {
            return Err(format!("Invalid range: start ({}) > end ({})", start, end));
        }

        Ok(LineRange { start, end })
    } else {
        // Single line number
        let line = s.parse::<usize>()
            .map_err(|_| format!("Invalid line number: {}", s))?;
        Ok(LineRange { start: line, end: line })
    }
}

fn merge_ranges(ranges: Vec<LineRange>) -> Vec<LineRange> {
    if ranges.is_empty() {
        return ranges;
    }

    let mut merged = Vec::new();
    let mut current = ranges[0].clone();

    for range in ranges.into_iter().skip(1) {
        if range.start <= current.end + 1 {
            // Overlapping or adjacent, merge
            current.end = current.end.max(range.end);
        } else {
            merged.push(current);
            current = range;
        }
    }
    merged.push(current);

    merged
}
```

### Selective Processing

```rust
pub fn process_with_line_ranges(
    config: &Config,
    input: &str,
) -> (String, ProcessingStats) {
    test_log!("INFO", "Processing with line ranges: {:?}", config.lines);

    let lines: Vec<&str> = input.lines().collect();
    let total_lines = lines.len();

    // Determine which lines to process
    let process_mask = if let Some(ref ranges) = config.lines {
        let mut mask = vec![false; total_lines];
        for range in ranges {
            let start = range.start.saturating_sub(1);  // Convert to 0-indexed
            let end = range.end.min(total_lines);
            for i in start..end {
                mask[i] = true;
            }
        }
        mask
    } else {
        vec![true; total_lines]  // Process all
    };

    test_log!("DEBUG", "Process mask: {} lines marked for processing",
        process_mask.iter().filter(|&&b| b).count());

    // Detect blocks only in marked regions
    let blocks = detect_blocks_with_mask(&lines, &process_mask);

    let mut output_lines: Vec<String> = lines.iter().map(|s| s.to_string()).collect();
    let mut stats = ProcessingStats::new();
    stats.total_lines = total_lines;

    for block in blocks {
        // Only process if block overlaps with ranges
        let block_in_range = (block.start..block.end).any(|i| process_mask.get(i).copied().unwrap_or(false));

        if !block_in_range {
            test_log!("DEBUG", "Skipping block at lines {}-{}: outside requested range", block.start + 1, block.end + 1);
            stats.blocks_skipped += 1;
            continue;
        }

        stats.blocks_found += 1;

        if block.confidence < config.effective_min_score() {
            stats.blocks_skipped += 1;
            continue;
        }

        stats.blocks_processed += 1;

        let (revised, revisions, skipped) = correct_block(config, &block, &output_lines);
        stats.revisions_applied += revisions;
        stats.revisions_skipped += skipped;

        for (i, line) in revised.iter().enumerate() {
            if block.start + i < output_lines.len() {
                output_lines[block.start + i] = line.clone();
            }
        }
    }

    (output_lines.join("\n"), stats)
}
