## Implementation

### Argument Definition (clap)
```rust
#[derive(Parser, Debug)]
pub struct Config {
    /// Input files. Reads from stdin if not provided.
    #[arg(value_name = "FILE")]
    pub files: Vec<PathBuf>,

    // ... other args ...
}
```

### Processing Loop
```rust
fn run(config: &Config) -> anyhow::Result<RunResult> {
    let console = Console::new();

    if config.files.is_empty() {
        // Stdin mode
        let content = read_stdin()?;
        let result = process_content(&content, config)?;
        print!("{}", result.output);
        return Ok(RunResult::single(result));
    }

    // Multi-file mode
    let mut results = Vec::new();
    let mut errors = Vec::new();

    for path in &config.files {
        match process_file(path, config, &console) {
            Ok(result) => results.push((path.clone(), result)),
            Err(e) => {
                errors.push((path.clone(), e));
                if config.verbose {
                    eprintln!("[red]Error processing {}:[/] {}", path.display(), e);
                }
            }
        }
    }

    // Summary in verbose mode
    if config.verbose && config.files.len() > 1 {
        let total_files = config.files.len();
        let success = results.len();
        let failed = errors.len();
        let total_revisions: usize = results.iter().map(|(_, r)| r.revisions_applied).sum();

        console.print(&format!(
            "\n[bold]Summary:[/] {} file(s) processed, {} revision(s), {} error(s)",
            success, total_revisions, failed
        ));
    }

    // Return error if any file failed
    if !errors.is_empty() {
        anyhow::bail!(
            "{} file(s) had errors: {}",
            errors.len(),
            errors.iter()
                .map(|(p, _)| p.display().to_string())
                .collect::<Vec<_>>()
                .join(", ")
        );
    }

    Ok(RunResult::multi(results))
}
```

### Output Modes

#### Default (stdout)
```rust
// Each file's output concatenated to stdout
for (path, result) in &results {
    if config.files.len() > 1 && !config.in_place {
        // Add file separator for multi-file output
        println!("==> {} <==", path.display());
    }
    print!("{}", result.output);
}
```

#### In-place (-i)
```rust
// Each file modified independently
for path in &config.files {
    let content = fs::read_to_string(path)?;
    let result = process_content(&content, config)?;
    fs::write(path, &result.output)?;
}
```

#### With --diff
```rust
// Diff for each file
for (path, result) in &results {
    if result.changed {
        let original = fs::read_to_string(path)?;
        print_diff(&original, &result.output, path);
    }
}
```

