```bash
#!/usr/bin/env bash
set -euo pipefail

# E2E Test Runner for aadc
# Usage: ./tests/e2e_runner.sh [--verbose] [--filter PATTERN]

SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
PROJECT_ROOT="$(dirname "$SCRIPT_DIR")"
AADC_BIN="${PROJECT_ROOT}/target/release/aadc"
FIXTURES_DIR="${SCRIPT_DIR}/fixtures"
LOG_FILE="${SCRIPT_DIR}/e2e_results.log"

# Colors for output
RED='\033[0;31m'
GREEN='\033[0;32m'
YELLOW='\033[1;33m'
BLUE='\033[0;34m'
NC='\033[0m' # No Color

VERBOSE=false
FILTER=""
PASSED=0
FAILED=0
SKIPPED=0

# Parse arguments
while [[ $# -gt 0 ]]; do
    case $1 in
        --verbose|-v)
            VERBOSE=true
            shift
            ;;
        --filter|-f)
            FILTER="$2"
            shift 2
            ;;
        *)
            echo "Unknown option: $1"
            exit 1
            ;;
    esac
done

log() {
    local level="$1"
    shift
    local msg="$*"
    local timestamp=$(date '+%Y-%m-%d %H:%M:%S')

    echo "[${timestamp}] [${level}] ${msg}" >> "$LOG_FILE"

    if [[ "$VERBOSE" == "true" ]] || [[ "$level" == "ERROR" ]] || [[ "$level" == "RESULT" ]]; then
        case "$level" in
            ERROR)   echo -e "${RED}[${level}]${NC} ${msg}" ;;
            PASS)    echo -e "${GREEN}[${level}]${NC} ${msg}" ;;
            FAIL)    echo -e "${RED}[${level}]${NC} ${msg}" ;;
            SKIP)    echo -e "${YELLOW}[${level}]${NC} ${msg}" ;;
            INFO)    echo -e "${BLUE}[${level}]${NC} ${msg}" ;;
            RESULT)  echo -e "${BLUE}[${level}]${NC} ${msg}" ;;
            *)       echo "[${level}] ${msg}" ;;
        esac
    fi
}

# Ensure binary exists
if [[ ! -f "$AADC_BIN" ]]; then
    log "INFO" "Building aadc in release mode..."
    cargo build --release --manifest-path "${PROJECT_ROOT}/Cargo.toml"
fi

# Initialize log
echo "=== E2E Test Run: $(date) ===" > "$LOG_FILE"
log "INFO" "Using binary: $AADC_BIN"
log "INFO" "Fixtures directory: $FIXTURES_DIR"

# Run a single test case
run_test() {
    local test_name="$1"
    local input_file="$2"
    local expected_file="$3"
    local extra_args="${4:-}"

    # Apply filter if specified
    if [[ -n "$FILTER" ]] && [[ ! "$test_name" =~ $FILTER ]]; then
        ((SKIPPED++))
        log "SKIP" "$test_name (filtered out)"
        return 0
    fi

    log "INFO" "Running test: $test_name"
    log "DEBUG" "  Input: $input_file"
    log "DEBUG" "  Expected: $expected_file"
    log "DEBUG" "  Extra args: $extra_args"

    # Run aadc and capture output
    local actual_output
    local exit_code=0

    if [[ -n "$extra_args" ]]; then
        actual_output=$("$AADC_BIN" $extra_args "$input_file" 2>&1) || exit_code=$?
    else
        actual_output=$("$AADC_BIN" "$input_file" 2>&1) || exit_code=$?
    fi

    log "DEBUG" "  Exit code: $exit_code"

    if [[ $exit_code -ne 0 ]]; then
        log "FAIL" "$test_name - aadc exited with code $exit_code"
        log "DEBUG" "  Output: $actual_output"
        ((FAILED++))
        return 1
    fi

    # Compare output with expected
    local expected_output
    expected_output=$(cat "$expected_file")

    if [[ "$actual_output" == "$expected_output" ]]; then
        log "PASS" "$test_name"
        ((PASSED++))
        return 0
    else
        log "FAIL" "$test_name - output mismatch"
        log "DEBUG" "  === Expected ==="
        log "DEBUG" "$expected_output"
        log "DEBUG" "  === Actual ==="
        log "DEBUG" "$actual_output"
        log "DEBUG" "  === Diff ==="
        diff <(echo "$expected_output") <(echo "$actual_output") >> "$LOG_FILE" 2>&1 || true
        ((FAILED++))
        return 1
    fi
}

# ============================================
# TEST SUITE: Basic Functionality
# ============================================

log "INFO" "=== TEST SUITE: Basic Functionality ==="

run_test "basic_ascii_box" \
    "${FIXTURES_DIR}/basic/ascii_box.input.txt" \
    "${FIXTURES_DIR}/basic/ascii_box.expected.txt"

run_test "basic_unicode_box" \
